#include<cstdio>
int ans;
void f(int a,int k){
	//a表示当前这个数，k表示除数 
	if(a%k==0){//能被整除 
		if(a/k==1) {
			//如果整除后得1，则记录答案，不用继续分解 
			ans=k;
			return;
		}
		f(a/k,k);//整除 
	}else{
		f(a,k+1);//尝试下一个数 
	} 
}
int main(){
	int n,m;
	scanf("%d%d",&n,&m);//输入 
	while(n<=m){
		f(n,2);//调用函数 
		printf("%d",ans);//输出答案 
		if(n!=m) printf(",");//特判是否需要逗号 
		n++;
	}
	return 0;
}
